solution_code:
#include <stdio.h>

void swap_int_ptr(int **a, int **b) {
    int *tmp = *a;
    *a = *b;
    *b = tmp;
}

int main(void) {
    {
        int x = 10, y = 20;
        int *p = &x, *q = &y;
        swap_int_ptr(&p, &q);
        printf("%d\n", (int)(*p));
        printf("%d\n", (int)(*q));
    }
    {
        int a = -5, b = 15;
        int *pa = &a, *pb = &b;
        swap_int_ptr(&pa, &pb);
        printf("%d\n", (int)(*pa));
        printf("%d\n", (int)(*pb));
    }
    {
        int z = 99;
        int *p = &z, *q = &z;
        swap_int_ptr(&p, &q);
        printf("%d\n", (int)(*p));
        printf("%d\n", (int)(*q));
    }
    {
        int x = 1, y = 2;
        int *p = &x, *q = &y;
        swap_int_ptr(&p, &q);
        printf("%d\n", (int)(*p));
        swap_int_ptr(&p, &q);
        printf("%d\n", (int)(*p));
    }
    return 0;
}

